func (b Builder) Build(ctx context.Context, input BuildInput) (State, error) {
	span := tracex.Start[State](ctx, b.tracer, "billing.worker.subscription.sync.targetstate.Build")
	return span.Wrap(func(ctx context.Context) (State, error) {
		if err := input.Validate(); err != nil { return State{}, fmt.Errorf("validating input: %w", err) }
		if input.SubscriptionView == nil { return State{MaxGenerationTimeLimit: input.AsOf}, nil }
		subs := *input.SubscriptionView
		upcomingLinesResult, err := b.collectUpcomingLines(ctx, subs, input.AsOf)
		if err != nil { return State{}, fmt.Errorf("collecting upcoming lines: %w", err) }
		inScopeLines, err := b.correctPeriodStartForUpcomingLines(ctx, subs.Subscription.ID, upcomingLinesResult.Lines, input.Persisted)
		if err != nil { return State{}, err }
		currencyCalculator, err := subs.Subscription.Currency.Calculator()
		if err != nil { return State{}, err }
		return State{Items: lo.Map(inScopeLines, func(item SubscriptionItemWithPeriods, _ int) StateItem {
			return StateItem{SubscriptionItemWithPeriods: item, CurrencyCalculator: currencyCalculator, Subscription: subs.Subscription}
		}), MaxGenerationTimeLimit: upcomingLinesResult.SubscriptionMaxGenerationTimeLimit}, nil
	})
}
